import "core-js/modules/es.array.push.js";
import "core-js/modules/es.iterator.constructor.js";
import "core-js/modules/es.iterator.every.js";
import "core-js/modules/es.iterator.filter.js";
import "core-js/modules/es.iterator.find.js";
import "core-js/modules/es.iterator.some.js";
import Player from "@/components/Lobby/Player.vue";
import SideBar from "@/components/SideBar.vue";
import ChatMessage from "@/components/Lobby/ChatMessage.vue";
import { mapState } from "vuex";
export default {
  components: {
    Player,
    ChatMessage,
    SideBar
  },
  data() {
    return {
      lastMessages: null,
      queueNumber: "-",
      // 强制开启人机模式
      forceBotMode: true
    };
  },
  computed: {
    ...mapState({
      players1: state => state.lobby.members ? state.lobby.members.filter(c => c.lobbyTeam === "TEAM1") : undefined,
      players2: state => state.lobby.members ? state.lobby.members.filter(c => c.lobbyTeam === "TEAM2") : undefined,
      lobbyChatMessages: state => state.lobbyChatMessages,
      lobbyInvites: state => state.lobby.invited,
      inQueue: state => state.lobby.inQueue,
      owner: state => state.lobbyOwner,
      serverCount: state => state.serverCount,
      isBotGame: state => {
        const value = state.lobby.isBotGame || false;
        console.log("isBotGame from store:", value);
        return value;
      },
      botDifficulty: state => {
        const difficulty = state.lobby.botDifficulty || "INTERMEDIATE";
        console.log("botDifficulty from store:", difficulty);
        return difficulty;
      },
      currentLobbyPlayer: state => {
        return state.lobby.members.filter(member => {
          return member.summonerName == state.user.summonerName;
        })[0];
      },
      isHumanPlayer: state => {
        if (!state.lobby.isBotGame && !this.forceBotMode) return true;
        const currentUser = state.user.summonerName;
        return state.lobby.members.some(member => member.summonerName === currentUser && !member.isAI);
      },
      humanPlayersCount: state => {
        if (!state.lobby.isBotGame && !this.forceBotMode) return 0;
        return state.lobby.members.filter(member => !member.isAI).length;
      },
      canStartGame: state => {
        if (!state.lobby.isBotGame && !this.forceBotMode) return true;
        return state.lobby.members.some(member => !member.isAI);
      }
    }),
    canSwitchTeam() {
      if (this.isBotGame || this.forceBotMode) return false;
      if (this.players1 && this.players2) {
        let user = this.$store.state.user.summonerName;
        let team1 = this.players1.some(c => c.summonerName == user);
        let team2 = this.players2.some(c => c.summonerName == user);
        if (team1 && this.players2.length <= 5) {
          return true;
        } else if (team2 && this.players1.length <= 5) {
          return true;
        }
      }
      return false;
    },
    // 控制机器人按钮显示
    shouldShowBotControls() {
      const shouldShow = (this.isBotGame || this.forceBotMode) && this.owner;
      console.log("shouldShowBotControls:", shouldShow);
      return shouldShow;
    }
  },
  methods: {
    getMaxTeamSize() {
      const teamSize = this.getTeamSize();
      if (teamSize === "5x5") return 5;
      if (teamSize === "3x3") return 3;
      return 5;
    },
    isTeamFull(teamNumber) {
      const team = teamNumber === 1 ? this.players1 : this.players2;
      return team && team.length >= this.getMaxTeamSize();
    },
    hasBotInTeam(teamNumber) {
      const team = teamNumber === 1 ? this.players1 : this.players2;
      return team && team.some(player => player.isAI === true);
    },
    isTeamAI(teamNumber) {
      const team = teamNumber === 1 ? this.players1 : this.players2;
      if (!team || team.length === 0) return false;
      return team.every(player => player.isAI === true);
    },
    getBotDifficultyText() {
      const difficulties = {
        BEGINNER: this.$translate.text("PLAY_DATA_DIFFICULTY_BEGINNER") || "入门",
        INTERMEDIATE: this.$translate.text("PLAY_DATA_DIFFICULTY_INTERMEDIATE") || "中等",
        ADVANCED: this.$translate.text("PLAY_DATA_DIFFICULTY_ADVANCED") || "高级"
      };
      const diff = this.botDifficulty || "INTERMEDIATE";
      return difficulties[diff] || difficulties.INTERMEDIATE;
    },
    getBotDifficultyDescription() {
      const descriptions = {
        BEGINNER: this.$translate.text("LOBBY_AI_DIFFICULTY_BEGINNER_DESC") || "AI 对手较为简单，适合新手练习",
        INTERMEDIATE: this.$translate.text("LOBBY_AI_DIFFICULTY_INTERMEDIATE_DESC") || "AI 对手有中等水平，适合普通玩家",
        ADVANCED: this.$translate.text("LOBBY_AI_DIFFICULTY_ADVANCED_DESC") || "AI 对手较为强大，适合进阶玩家"
      };
      const diff = this.botDifficulty || "INTERMEDIATE";
      return descriptions[diff] || this.$translate.text("LOBBY_AI_DEFAULT_DESC") || "与电脑AI进行对战";
    },
    getStartButtonText() {
      if (this.isBotGame || this.forceBotMode) {
        if (!this.canStartGame) {
          return this.$translate.text("LOBBY_NEED_MORE_PLAYERS") || "等待玩家加入";
        }
        return this.$translate.text("CTLOBBY_START_GAME_BTN") || "开始游戏";
      }
      return this.$translate.text("CTLOBBY_START_GAME_BTN") || "开始游戏";
    },
    getChatPlaceholder() {
      if ((this.isBotGame || this.forceBotMode) && !this.isHumanPlayer) {
        return this.$translate.text("LOBBY_AI_CANNOT_CHAT") || "AI 无法发送消息";
      }
      return this.$translate.text("LOBBY_ALLCHAT_PLACEHOLDER") || "输入消息...";
    },
    canJoinTeam(team) {
      if (this.isBotGame || this.forceBotMode) return false;
      if (this.players1 && this.players2) {
        if (team == 2) {
          return this.players2.length != 5 && this.currentLobbyPlayer.lobbyTeam == "TEAM1" && this.canSwitchTeam;
        } else {
          return this.players1.length != 5 && this.currentLobbyPlayer.lobbyTeam == "TEAM2" && this.canSwitchTeam;
        }
      } else {
        return false;
      }
    },
    getInviteStatus(status) {
      return this.$translate.text(`LOBBY_INVITE_STATUS_${status}`);
    },
    inLobby(invite) {
      return this.$store.state.lobby.members.filter(member => {
        return member.summonerName == invite.summonerName;
      }).length > 0;
    },
    getQueueType() {
      if (this.isBotGame || this.forceBotMode) {
        return this.$translate.text("LOBBY_MAP_OPTIONS_VALUE_BOT") || "人机对战";
      }
      switch (this.$store.state.lobby.lobbyType) {
        case "SUMMONERS_RIFT_DRAFT":
        case "TWISTED_TREELINE_DRAFT":
          return this.$translate.text("LOBBY_MAP_OPTIONS_VALUE_QT_DRAFT") || "经典 (征召)";
        case "SUMMONERS_RIFT_BLIND":
        case "TWISTED_TREELINE_BLIND":
          return this.$translate.text("LOBBY_MAP_OPTIONS_VALUE_QT_BLIND") || "经典 (盲选)";
        case "ARAM_BLIND":
          return this.$translate.text("LOBBY_MAP_OPTIONS_VALUE_QT_ARAM") || "经典 (随机选择)";
        default:
          return "";
      }
    },
    getMapPreview() {
      if ((this.isBotGame || this.forceBotMode) && this.$store.state.lobby.mapCode) {
        const mapCode = this.$store.state.lobby.mapCode;
        if (mapCode === "SUMMONERS_RIFT") {
          return "static/images/general/sr-preview.png";
        } else if (mapCode === "TWISTED_TREELINE") {
          return "static/images/general/tt-preview.png";
        } else if (mapCode === "ARAM") {
          return "static/images/general/ha-preview.png";
        }
      }
      const lobbyType = this.$store.state.lobby.lobbyType;
      if (lobbyType && lobbyType.includes("SUMMONERS_RIFT")) {
        return "static/images/general/sr-preview.png";
      } else if (lobbyType && lobbyType.includes("TWISTED_TREELINE")) {
        return "static/images/general/tt-preview.png";
      } else if (lobbyType && lobbyType.includes("ARAM")) {
        return "static/images/general/ha-preview.png";
      }
      return "static/images/general/sr-preview.png";
    },
    getMapType() {
      if ((this.isBotGame || this.forceBotMode) && this.$store.state.lobby.mapCode) {
        const mapCode = this.$store.state.lobby.mapCode;
        if (mapCode === "SUMMONERS_RIFT") {
          return this.$translate.text("LOBBY_MAP_OPTIONS_VALUE_SR") || "召唤师峡谷";
        } else if (mapCode === "TWISTED_TREELINE") {
          return this.$translate.text("LOBBY_MAP_OPTIONS_VALUE_TT") || "扭曲丛林";
        } else if (mapCode === "ARAM") {
          return this.$translate.text("LOBBY_MAP_OPTIONS_VALUE_HA") || "嚎哭深渊";
        }
      }
      const lobbyType = this.$store.state.lobby.lobbyType;
      if (lobbyType && lobbyType.includes("SUMMONERS_RIFT")) {
        return this.$translate.text("LOBBY_MAP_OPTIONS_VALUE_SR") || "召唤师峡谷";
      } else if (lobbyType && lobbyType.includes("TWISTED_TREELINE")) {
        return this.$translate.text("LOBBY_MAP_OPTIONS_VALUE_TT") || "扭曲丛林";
      } else if (lobbyType && lobbyType.includes("ARAM")) {
        return this.$translate.text("LOBBY_MAP_OPTIONS_VALUE_HA") || "嚎哭深渊";
      }
      return this.$translate.text("LOBBY_MAP_OPTIONS_VALUE_SR") || "召唤师峡谷";
    },
    getTeamSize() {
      if ((this.isBotGame || this.forceBotMode) && this.$store.state.lobby.teamSize) {
        return this.$store.state.lobby.teamSize;
      }
      const lobbyType = this.$store.state.lobby.lobbyType;
      if (lobbyType && (lobbyType.includes("SUMMONERS_RIFT") || lobbyType.includes("ARAM"))) {
        return "5x5";
      } else if (lobbyType && lobbyType.includes("TWISTED_TREELINE")) {
        return "3x3";
      }
      return "5x5";
    },
    addBotToTeam(teamNumber) {
      console.log("addBotToTeam called for team:", teamNumber);
      if (this.isTeamFull(teamNumber)) {
        this.$modal.setter.show({
          title: this.$translate.text("CTLOBBY_CANNOT_ADD_BOT") || "无法添加机器人",
          body: this.$translate.text("CTLOBBY_TEAM_FULL_DESC") || "该队伍已达到最大人数限制",
          footer: this.$translate.text("GENERAL_OK") || "确定"
        });
        return;
      }
      const team = teamNumber === 1 ? "TEAM1" : "TEAM2";
      const teamPlayers = teamNumber === 1 ? this.players1 : this.players2;
      const botCount = teamPlayers.filter(p => p.isAI).length;
      const botData = {
        isAI: true,
        aiDifficulty: this.botDifficulty || "INTERMEDIATE",
        summonerName: `${this.getBotDifficultyText()} AI ${botCount + 1}`,
        summonerLevel: 30,
        summonerIconId: Math.floor(Math.random() * 30) + 1,
        lobbyTeam: team,
        isReady: true
      };
      console.log("Sending LOBBY_ADD_BOT with data:", botData);
      this.$socket.sendLobbyMessage("LOBBY_ADD_BOT", {
        data: botData
      }, (response, error) => {
        if (error) {
          console.log("Flyback error:", error);
          this.$modal.setter.show({
            title: this.$translate.text("CTLOBBY_ADD_BOT_FAILED") || "添加机器人失败",
            body: error.message || this.$translate.text("CTLOBBY_ADD_BOT_FAILED_DESC") || "无法添加机器人到队伍",
            footer: this.$translate.text("GENERAL_OK") || "确定"
          });
        } else {
          console.log("Bot added successfully:", response);
        }
      });
    },
    removeBotFromTeam(teamNumber) {
      console.log("removeBotFromTeam called for team:", teamNumber);
      const team = teamNumber === 1 ? this.players1 : this.players2;
      const botToRemove = team.find(player => player.isAI === true);
      if (!botToRemove) return;
      console.log("Removing bot:", botToRemove.summonerName);
      this.$socket.sendLobbyMessage("LOBBY_REMOVE_BOT", {
        data: {
          summonerName: botToRemove.summonerName
        }
      }, (response, error) => {
        if (error) {
          console.log("Flyback error:", error);
          this.$modal.setter.show({
            title: this.$translate.text("CTLOBBY_REMOVE_BOT_FAILED") || "移除机器人失败",
            body: error.message || this.$translate.text("CTLOBBY_REMOVE_BOT_FAILED_DESC") || "无法移除机器人",
            footer: this.$translate.text("GENERAL_OK") || "确定"
          });
        } else {
          console.log("Bot removed successfully:", response);
        }
      });
    },
    sendLobbyChatMessage() {
      if ((this.isBotGame || this.forceBotMode) && !this.isHumanPlayer) {
        return;
      }
      const message = this.$refs.chatInput.value;
      if (message.trim() == "") return;
      this.$refs.chatInput.value = "";
      this.$socket.sendLobbyMessage("LOBBY_CHAT", {
        data: message
      }, (response, error) => {
        if (error) {
          console.log("Flyback error:");
          console.log(error);
        }
        this.$nextTick(() => {
          if (this.$refs.chatMessages) {
            this.$refs.chatMessages.scrollTop = this.$refs.chatMessages.scrollHeight;
          }
        });
      });
    },
    leaveLobby() {
      const route = this.$route.name;
      const router = this.$router;
      this.$socket.sendLobbyMessage("LOBBY_LEAVE", {}, (response, error) => {
        if (error) {
          console.log("Flyback error:");
          console.log(error);
        }
        if (route != "Home") {
          router.push("/LoggedIn/home");
        }
      });
    },
    startQueue() {
      if (this.inQueue) return;
      if (this.isBotGame || this.forceBotMode) {
        if (!this.canStartGame) {
          this.$modal.setter.show({
            title: this.$translate.text("LOBBY_CANNOT_START") || "无法开始",
            body: this.$translate.text("LOBBY_NEED_MORE_PLAYERS_DETAIL") || "人机模式需要至少1名玩家才能开始游戏",
            footer: this.$translate.text("GENERAL_OK") || "确定"
          });
          return;
        }
        console.log("Starting bot game with difficulty:", this.botDifficulty);
        this.$socket.sendLobbyMessage("LOBBY_START_BOT_GAME", {
          data: {
            difficulty: this.botDifficulty || "INTERMEDIATE"
          }
        }, (response, error) => {
          if (error) {
            console.log("Flyback error:");
            console.log(error);
            this.$modal.setter.show({
              title: this.$translate.text("LOBBY_START_FAILED") || "开始游戏失败",
              body: error.message || this.$translate.text("LOBBY_START_FAILED_DESC") || "无法开始游戏，请稍后重试",
              footer: this.$translate.text("GENERAL_OK") || "确定"
            });
          }
        });
        return;
      }
      this.$sound.template("OVERVIEW_PLAYBUTTON");
      this.$socket.sendLobbyMessage("LOBBY_MATCHMAKING_START", {}, (response, error) => {
        if (error) {
          console.log("Flyback error:");
          console.log(error);
          if (error && error.message && error.code === 140) {
            this.$store.dispatch("socketRecievedLobbyChat", {
              from: "SYSTEM",
              to: null,
              data: error.message
            });
          }
        }
        console.log(response);
      });
    },
    stopQueue() {
      this.$sound.template("OVERVIEW_CLICK");
      this.$store.dispatch("clearLobbyTimers");
      this.$socket.sendLobbyMessage("LOBBY_MATCHMAKING_STOP", {}, (response, error) => {
        if (error) {
          console.log("Flyback error:");
          console.log(error);
        }
        this.$store.dispatch("setLobbyQueueState", false);
        console.log(response);
      });
    },
    switchTeam() {
      if (this.inQueue) return;
      this.$socket.sendLobbyMessage("LOBBY_SWITCH_TEAM", {}, (response, error) => {
        if (error) {
          console.log("Flyback error:");
          console.log(error);
        }
      });
    },
    t(key, params) {
      return this.$translate.text(key, params);
    },
    tWithParams(key, params) {
      return this.$translate.text(key, params);
    }
  },
  beforeMount() {
    this.$store.dispatch("saveUserStatus", "IN_LOBBY");
    this.$store.dispatch("changeBackgroundState", "CUSTOM_LOBBY");
  },
  mounted() {
    console.log("LobbyCustom mounted");
    console.log("isBotGame:", this.isBotGame);
    console.log("owner:", this.owner);
    console.log("forceBotMode:", this.forceBotMode);
    this.$nextTick(() => {
      if (this.$refs.chatMessages) {
        this.$refs.chatMessages.scrollTop = this.$refs.chatMessages.scrollHeight;
      }
    });
  },
  updated() {
    if (this.lastMessages !== this.lobbyChatMessages.length) {
      this.lastMessages = this.lobbyChatMessages.length;
      this.$nextTick(() => {
        if (this.$refs.chatMessages) {
          this.$refs.chatMessages.scrollTop = this.$refs.chatMessages.scrollHeight;
        }
      });
    }
  },
  created() {
    this.$store.dispatch("getServerCount");
  }
};
